/// //////////////////////////////////////////////////////////////////////////////
///
/// 一. SDK 接口常用配置选项
///
/// //////////////////////////////////////////////////////////////////////////////
/// 1.1 调用接口的返回值（若接口参数中有回调，只有当接口返回 TIM_SUCC 时，回调才会被调用）
enum TIMResult {
  /// 接口调用成功
  TIM_SUCC(0),

  /// 接口调用失败，ImSDK 未初始化
  TIM_ERR_SDKUNINIT(-1),

  /// 接口调用失败，用户未登录
  TIM_ERR_NOTLOGIN(-2),

  /// 接口调用失败，错误的 Json 格式或 Json Key
  TIM_ERR_JSON(-3),

  /// 接口调用失败，参数错误
  TIM_ERR_PARAM(-4),

  /// 接口调用失败，无效的会话
  TIM_ERR_CONV(-5),

  /// 接口调用失败，无效的群组
  TIM_ERR_GROUP(-6);

  final int value;
  const TIMResult(this.value);

  static TIMResult fromValue(int value) {
    switch (value) {
      case 0: return TIM_SUCC;
      case -1: return TIM_ERR_SDKUNINIT;
      case -2: return TIM_ERR_NOTLOGIN;
      case -3: return TIM_ERR_JSON;
      case -4: return TIM_ERR_PARAM;
      case -5: return TIM_ERR_CONV;
      case -6: return TIM_ERR_GROUP;
      default: throw ArgumentError("Unknown value for TIMResult: $value");
    }
  }
}

/// 1.2 会话类型
enum TIMConvType {
  /// 无效会话
  kTIMConv_Invalid(0),

  /// 个人会话
  kTIMConv_C2C(1),

  /// 群组会话
  kTIMConv_Group(2),

  /// 系统会话，已废弃
  kTIMConv_System(3);

  final int value;
  const TIMConvType(this.value);

  static TIMConvType fromValue(int value) {
    switch (value) {
      case 0: return kTIMConv_Invalid;
      case 1: return kTIMConv_C2C;
      case 2: return kTIMConv_Group;
      case 3: return kTIMConv_System;
      default: throw ArgumentError("Unknown value for TIMConvType: $value");
    }
  }
}

/// 1.3 消息接收选项
enum TIMReceiveMessageOpt {
  /// 在线正常接收消息，离线时会进行 APNs 推送
  kTIMRecvMsgOpt_Receive(0),

  /// 不会接收到消息，离线不会有推送通知
  kTIMRecvMsgOpt_Not_Receive(1),

  /// 在线正常接收消息，离线不会有推送通知
  kTIMRecvMsgOpt_Not_Notify(2),

  /// 在线接收消息，离线只接收 at 消息的推送
  kTIMRecvMsgOpt_Not_Notify_Except_At(3),

  /// 在线和离线都只接收@消息
  kTIMRecvMsgOpt_Not_Receive_Except_At(4);

  final int value;
  const TIMReceiveMessageOpt(this.value);

  static TIMReceiveMessageOpt fromValue(int value) {
    switch (value) {
      case 0: return kTIMRecvMsgOpt_Receive;
      case 1: return kTIMRecvMsgOpt_Not_Receive;
      case 2: return kTIMRecvMsgOpt_Not_Notify;
      case 3: return kTIMRecvMsgOpt_Not_Notify_Except_At;
      case 4: return kTIMRecvMsgOpt_Not_Receive_Except_At;
      default: throw ArgumentError("Unknown value for TIMReceiveMessageOpt: $value");
    }
  }
}

